// VIKS Animation Library
(function() {
  // Animation configurations
  const animations = {
    // Bounce animations
    bounce: {
      from: { transform: 'translate3d(0, 0, 0)' },
      '50%': { transform: 'translate3d(0, -30px, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'bounce-up': {
      from: { transform: 'translate3d(0, 100px, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'bounce-down': {
      from: { transform: 'translate3d(0, -100px, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'bounce-left': {
      from: { transform: 'translate3d(100px, 0, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'bounce-right': {
      from: { transform: 'translate3d(-100px, 0, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    // Fade animations
    fade: {
      from: { opacity: 0 },
      to: { opacity: 1 }
    },
    'fade-up': {
      from: { opacity: 0, transform: 'translate3d(0, 100%, 0)' },
      to: { opacity: 1, transform: 'translate3d(0, 0, 0)' }
    },
    'fade-down': {
      from: { opacity: 0, transform: 'translate3d(0, -100%, 0)' },
      to: { opacity: 1, transform: 'translate3d(0, 0, 0)' }
    },
    'fade-left': {
      from: { opacity: 0, transform: 'translate3d(100%, 0, 0)' },
      to: { opacity: 1, transform: 'translate3d(0, 0, 0)' }
    },
    'fade-right': {
      from: { opacity: 0, transform: 'translate3d(-100%, 0, 0)' },
      to: { opacity: 1, transform: 'translate3d(0, 0, 0)' }
    },
    // Flip animations
    'flip-up': {
      from: { transform: 'perspective(400px) rotateX(90deg)' },
      to: { transform: 'perspective(400px) rotateX(0)' }
    },
    'flip-down': {
      from: { transform: 'perspective(400px) rotateX(-90deg)' },
      to: { transform: 'perspective(400px) rotateX(0)' }
    },
    'flip-left': {
      from: { transform: 'perspective(400px) rotateY(-90deg)' },
      to: { transform: 'perspective(400px) rotateY(0)' }
    },
    'flip-right': {
      from: { transform: 'perspective(400px) rotateY(90deg)' },
      to: { transform: 'perspective(400px) rotateY(0)' }
    },
    // Slide animations
    'slide-up': {
      from: { transform: 'translate3d(0, 100%, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'slide-down': {
      from: { transform: 'translate3d(0, -100%, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'slide-left': {
      from: { transform: 'translate3d(100%, 0, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    'slide-right': {
      from: { transform: 'translate3d(-100%, 0, 0)' },
      to: { transform: 'translate3d(0, 0, 0)' }
    },
    // Zoom animations
    'zoom-in': {
      from: { opacity: 0, transform: 'scale3d(0.3, 0.3, 0.3)' },
      to: { opacity: 1, transform: 'scale3d(1, 1, 1)' }
    },
    'zoom-out': {
      from: { opacity: 1, transform: 'scale3d(1, 1, 1)' },
      '50%': { opacity: 0, transform: 'scale3d(0.3, 0.3, 0.3)' },
      to: { opacity: 0 }
    }
  };

  // Helper functions
  function isElementInViewport(el) {
    const rect = el.getBoundingClientRect();
    return (
      rect.top >= 0 &&
      rect.left >= 0 &&
      rect.bottom <= (window.innerHeight || document.documentElement.clientHeight) &&
      rect.right <= (window.innerWidth || document.documentElement.clientWidth)
    );
  }

  function applyAnimation(element, animationName, duration = 1000, delay = 0) {
    const keyframes = animations[animationName];
    if (!keyframes) return;

    element.style.opacity = '0';
    element.style.animation = 'none';
    
    setTimeout(() => {
      element.style.opacity = '1';
      element.style.animation = `${animationName} ${duration}ms ease-in-out ${delay}ms forwards`;
      element.style.visibility = 'visible';
    }, 0);
  }

  // Initialize animations
  function initViks() {
    // Add keyframe animations to stylesheet
    const styleSheet = document.createElement('style');
    document.head.appendChild(styleSheet);

    Object.entries(animations).forEach(([name, keyframes]) => {
      const keyframeDefinition = `
        @keyframes ${name} {
          ${Object.entries(keyframes).map(([key, value]) => 
            `${key} { ${Object.entries(value).map(([prop, val]) => 
              `${prop}: ${val}`).join('; ')} }`
          ).join('\n')}
        }
      `;
      styleSheet.sheet.insertRule(keyframeDefinition, styleSheet.sheet.cssRules.length);
    });

    // Handle elements with data-viks attributes
    function handleAnimations() {
      const elements = document.querySelectorAll('[data-viks], [data-vik-cb]');
      
      elements.forEach(element => {
        if (isElementInViewport(element) && !element.classList.contains('viks-animated')) {
          const callback = element.getAttribute('data-vik-cb');
          
          if (callback) {
            const [animation, durationAttr, delayAttr] = callback.split(' ');
            const duration = parseInt(durationAttr?.split('-')[1]) || 1000;
            const delay = parseInt(delayAttr?.split('-')[1]) || 0;
            applyAnimation(element, animation, duration, delay);
          } else {
            const animation = element.getAttribute('data-viks');
            const duration = parseInt(element.getAttribute('data-viks-dr')) || 1000;
            const delay = parseInt(element.getAttribute('data-viks-dy')) || 0;
            applyAnimation(element, animation, duration, delay);
          }
          
          element.classList.add('viks-animated');
        }
      });
    }

    // Add scroll and resize event listeners
    window.addEventListener('scroll', handleAnimations);
    window.addEventListener('resize', handleAnimations);
    
    // Initial check for animations
    handleAnimations();
  }

  // Initialize when DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initViks);
  } else {
    initViks();
  }
})();